function softmax(x) {
    var size = x.length;
    var result = new Array(size);
    var max = x[0];
    for (var i = 1; i < size; ++i) {
        if (x[i] > max)
            max = x[i];
    }
    var sum = 0.0;
    for (var i = 0; i < size; ++i) {
        result[i] = Math.exp(x[i] - max);
        sum += result[i];
    }
    for (var i = 0; i < size; ++i)
        result[i] /= sum;
    return result;
}


// Panel arayüzü: maç verisinden W/D/L olasılığı döndürür
// girdi: {ax, rax, xgot, rxgot, sut, rsut, bf, rbf, ci, rci, rc, kurt}
function lgbmTahmin(mac) {
  // türetilmiş özellikler
  var fark_ax = (mac.ax||0) - (mac.rax||0);
  var fark_xgot = (mac.xgot||0) - (mac.rxgot||0);
  var fark_bf = (mac.bf||0) - (mac.rbf||0);
  var deger = {
    ax:mac.ax||0, rax:mac.rax||0, xgot:mac.xgot||0, rxgot:mac.rxgot||0,
    sut:mac.sut||0, rsut:mac.rsut||0, bf:mac.bf||0, rbf:mac.rbf||0,
    ci:mac.ci||0, rci:mac.rci||0, rc:mac.rc||0, kurt:mac.kurt||0,
    
    fark_ax:fark_ax, fark_xgot:fark_xgot, fark_bf:fark_bf
  };
  // özellik dizisini doğru sırayla kur
  var f = LGBM_OZELLIKLER.map(function(k){ return deger[k]; });
  // lgbmRaw ZATEN softmax uygulanmış olasılık döndürür [L, D, W] (toplamı ~1)
  // (ÖNEMLİ: tekrar softmax UYGULAMA — çift softmax güveni ezer!)
  var p = lgbmRaw(f);
  var pL=p[0], pD=p[1], pW=p[2];
  // güvenlik: toplamı 1'e normalize et (yuvarlama payı)
  var top=pL+pD+pW;
  if(top>0){ pL/=top; pD/=top; pW/=top; }
  // tahmin + güven
  var enYuksek=Math.max(pL,pD,pW);
  var tahmin = enYuksek===pW ? 'W' : (enYuksek===pL ? 'L' : 'D');
  return {
    tahmin: tahmin,
    guven: Math.round(enYuksek*100),
    pW: Math.round(pW*100),
    pD: Math.round(pD*100),
    pL: Math.round(pL*100)
  };
}
